class TestInsertLogApiLimits:
    async def test_inserts_and_extracts_normalized_fields(self, db) -> None:
        log_id, fields = await schema.insert_log_api_limits(
            db,
            received_at=100.0,
            received_by="limits-fetcher",
            raw_response=json.dumps(_SAMPLE_RAW),
        )
        await db.commit()

        assert isinstance(log_id, int) and log_id > 0
        assert fields["five_hour_utilization"] == 11.0
        assert fields["seven_day_utilization"] == 8.0
        # ISO 8601 normalized to epoch seconds
        assert isinstance(fields["five_hour_resets_at"], float)
        assert isinstance(fields["seven_day_resets_at"], float)

        cursor = await db.execute(
            "SELECT * FROM claude_log_api_limits WHERE id = ?", (log_id,)
        )
        row = dict(await cursor.fetchone())
        assert row["received_at"] == 100.0
        assert row["received_by"] == "limits-fetcher"
        assert row["five_hour_utilization"] == 11.0
        assert row["seven_day_utilization"] == 8.0
        # raw_response preserved verbatim
        assert json.loads(row["raw_response"]) == _SAMPLE_RAW

    async def test_null_resets_at_handled(self, db) -> None:
        """API can return null resets_at when a bucket is unused."""
        raw = {
            "five_hour": {"utilization": 0.0, "resets_at": None},
            "seven_day": {"utilization": 0.0, "resets_at": None},
        }
        _, fields = await schema.insert_log_api_limits(
            db,
            received_at=100.0,
            received_by="limits-fetcher",
            raw_response=json.dumps(raw),
        )
        await db.commit()
        assert fields["five_hour_resets_at"] is None
        assert fields["seven_day_resets_at"] is None

    async def test_missing_buckets_yield_nulls(self, db) -> None:
        """Empty/missing buckets normalize to None — not a crash."""
        _, fields = await schema.insert_log_api_limits(
            db,
            received_at=100.0,
            received_by="limits-fetcher",
            raw_response="{}",
        )
        await db.commit()
        assert fields["five_hour_utilization"] is None
        assert fields["five_hour_resets_at"] is None
        assert fields["seven_day_utilization"] is None
        assert fields["seven_day_resets_at"] is None

    async def test_unparseable_raw_does_not_crash(self, db) -> None:
        """Malformed JSON in raw_response stores the bytes but yields no fields."""
        log_id, fields = await schema.insert_log_api_limits(
            db,
            received_at=100.0,
            received_by="limits-fetcher",
            raw_response="not json",
        )
        await db.commit()
        assert log_id > 0
        assert fields["five_hour_utilization"] is None

        cursor = await db.execute(
            "SELECT raw_response FROM claude_log_api_limits WHERE id = ?",
            (log_id,),
        )
        row = await cursor.fetchone()
        # Original bytes preserved even when unparseable
        assert row["raw_response"] == "not json"


class TestLimitsFetchPath:
    """Successful API fetch in limits.py writes the v2 log row + broadcast."""

    async def test_writes_log_row_and_broadcasts(self, db, tmp_path) -> None:
        from agentpulse.platforms.claude import limits

        limits.reset_state()
        creds_dir = tmp_path / ".claude"
        creds_dir.mkdir()
        creds = creds_dir / ".credentials.json"
        creds.write_text(
            json.dumps({"claudeAiOauth": {"accessToken": "tk"}}),
            encoding="utf-8",
        )

        with (
            patch.object(limits, "_CREDENTIALS_PATH", creds),
            patch.object(limits, "_fetch_from_api", return_value=_SAMPLE_RAW),
            patch(
                "agentpulse.platforms.claude.limits.broadcast_api_limits_logged"
            ) as mock_bc,
        ):
            ok = await limits.get_limits(db)

        assert ok is True

        cursor = await db.execute(
            "SELECT * FROM claude_log_api_limits ORDER BY id DESC LIMIT 1"
        )
        row = dict(await cursor.fetchone())
        assert row["received_by"] == "limits-fetcher"
        assert row["five_hour_utilization"] == 11.0
        assert row["seven_day_utilization"] == 8.0

        mock_bc.assert_awaited_once()
        kwargs = mock_bc.call_args.kwargs
        assert kwargs["received_by"] == "limits-fetcher"
        assert kwargs["five_hour_utilization"] == 11.0
        assert kwargs["seven_day_utilization"] == 8.0
        assert isinstance(kwargs["log_id"], int) and kwargs["log_id"] > 0

        limits.reset_state()
